import * as stylex from "@stylexjs/stylex";
import type { BoxProps } from "../Box/box";
import { Box } from "../Box/box";
import {
	surfaceInteractiveStyles,
	surfaceVariantStyles,
} from "./surface.styles";

type SurfaceVariant = keyof typeof surfaceVariantStyles;
type SurfaceProps = BoxProps & {
	variant?: SurfaceVariant;
	interactive?: boolean;
};

function Surface({
	variant = "default",
	interactive,
	style,
	...props
}: SurfaceProps) {
	const resolvedStyles = stylex.props(
		surfaceVariantStyles[variant],
		interactive && surfaceInteractiveStyles.base,
		style,
	);
	return <Box {...props} {...resolvedStyles} />;
}

export type { SurfaceProps, SurfaceVariant };
export { Surface };

import * as stylex from "@stylexjs/stylex";
import { theme } from "@/lib/theme/contract.stylex";

export const surfaceVariantStyles = stylex.create({
	default: {
		backgroundColor: theme.surface,
		borderRadius: theme.borderRadius,
	},
	outline: {
		backgroundColor: theme.surface,
		borderWidth: 1,
		borderStyle: "solid",
		borderColor: theme.border,
	},
	raised: {
		backgroundColor: theme.surfaceRaised,
		boxShadow: theme.shadowMd,
	},
	sunken: {
		backgroundColor: theme.surfaceSubtle,
	},
});
export const surfaceInteractiveStyles = stylex.create({
	base: {
		cursor: "pointer",
		":hover": {
			backgroundColor: theme.surfaceHover,
		},
		":focus-visible": {
			outline: `2px solid ${theme.focusRing}`,
			outlineOffset: "2px",
		},
	},
});
